sortTasksByLearningPath(TASKS);
const db=createDb(),STATE_KEY="bergpredigt-tablet-state-v6";let sessionId=getActiveSession()||randomSession(),groupId="",taskIndex=0,solved=new Set(),completedGames=new Set(),attempts=0,locked=false,excluded=false,liveChannel=null,sessionRows=[],sessionCompletion=new Map(),groupTarget=4,lastPromptSeen="",selectedAvatar=AVATARS[0].id,finaleSeen=false,feedbackSeen=new Set(),localCards=[],groupNotes={};setActiveSession(sessionId);
function sanitizeGroupId(value){return value.trim().toLowerCase().replace(/[^a-z0-9_-]/g,"").slice(0,24)}
function stateId(){return`${STATE_KEY}:${sessionId}:${groupId}`}
function saveState(){if(groupId)localStorage.setItem(stateId(),JSON.stringify({taskIndex,solved:[...solved],completedGames:[...completedGames],cards:localCards,avatar:selectedAvatar,notes:groupNotes}))}
function restoreState(){try{const saved=JSON.parse(localStorage.getItem(stateId())||"{}");taskIndex=Math.min(Number(saved.taskIndex)||0,TASKS.length);solved=new Set(saved.solved||[]);completedGames=new Set(saved.completedGames||[]);localCards=saved.cards||[];selectedAvatar=saved.avatar||selectedAvatar;groupNotes=saved.notes||{}}catch{taskIndex=0;solved=new Set();completedGames=new Set();localCards=[];groupNotes={}}}
function saveAvatarState(){if(groupId){const saved=JSON.parse(localStorage.getItem(stateId())||"{}");localStorage.setItem(stateId(),JSON.stringify({...saved,avatar:selectedAvatar}))}}
function renderCollectionHud(){const hud=document.getElementById("collectionHud");if(!hud)return;const latest=localCards.slice(-3).reverse();hud.innerHTML=`<div class="card-chip"><b>Belegkarten</b><span>${localCards.length}</span><small>Für Tafelgespräch und Finale</small></div>${latest.map(card=>`<div class="value-chip"><b>${escapeHtml(card.type)}</b><span>${escapeHtml(card.name)}</span><small>Bibelbeleg im Plenum nutzen</small></div>`).join("")}`}
function selectAvatar(id){selectedAvatar=AVATARS.some(avatar=>avatar.id===id)?id:AVATARS[0].id;document.querySelectorAll("[data-avatar-choice]").forEach(button=>button.classList.toggle("selected",button.dataset.avatarChoice===selectedAvatar))}
function renderAvatarPicker(){document.getElementById("avatarPicker").innerHTML=AVATARS.map(avatar=>`<button class="avatar-choice ${avatar.id===selectedAvatar?"selected":""}" type="button" data-avatar-choice="${avatar.id}" aria-pressed="${avatar.id===selectedAvatar}"><span class="avatar-token" style="--avatar-pos:${avatar.pos}"></span><b>${avatar.name}</b></button>`).join("");document.querySelectorAll("[data-avatar-choice]").forEach(button=>button.addEventListener("click",()=>{selectAvatar(button.dataset.avatarChoice);document.querySelectorAll("[data-avatar-choice]").forEach(item=>item.setAttribute("aria-pressed",String(item.dataset.avatarChoice===selectedAvatar)))}))}
function stationPart(index){const sector=TASKS[index]?.sector;if(!sector)return{part:0,total:0};const tasks=TASKS.filter(task=>task.sector===sector),part=TASKS.slice(0,index+1).filter(task=>task.sector===sector).length;return{part,total:tasks.length}}
function renderFogMap(){const current=TASKS[taskIndex]?.sector,isCoop=activeWorkMode(sessionRows)==="cooperative";document.getElementById("tabletFogMap").innerHTML=SECTORS.map((sector,i)=>{const state=sessionCompletion.get(sector.id)||{count:0,required:isCoop?groupTarget:1,complete:false},isOwnDone=solved.has(sector.id),isCurrent=sector.id===current,label=state.complete||isOwnDone||isCurrent?sector.name:`Modul ${i+1}`,detail=state.complete?"gemeinsam erschlossen":isCoop?`${state.count}/${state.required} Gruppenbeiträge`:isCurrent?"jetzt spielen":"noch offen";return`<div class="${state.complete||isOwnDone?"done":""} ${isCurrent?"current":""}"><img src="${sector.art}" alt=""><b>${label}</b><span>${detail}</span></div>`}).join("")}
function tabletMapMarkup(){return`<section class="tablet-end-map"><h3>Euer Lernkreis</h3><p>Die Bergpredigt bleibt ein Ort: Die Module zeigen vier Zugänge zu Mt 5-7.</p><div>${SECTORS.map((sector,index)=>`<article class="${solved.has(sector.id)?"done":""}"><img src="${sector.art}" alt=""><b>${index+1}. ${escapeHtml(sector.name)}</b><span>${escapeHtml(sector.title)}</span></article>`).join("")}</div></section>`}
function showPromptPopup(prompt){if(!prompt||prompt===lastPromptSeen)return;lastPromptSeen=prompt;document.getElementById("promptPopupText").textContent=prompt;document.getElementById("promptPopup").classList.remove("hidden")}
function frameStoryFor(task,module,part){const sectorIndex=SECTORS.findIndex(sector=>sector.id===task.sector)+1,arc=STORY_CHAPTERS[task.sector],needle=ETHIK_KOMPASS.needles[task.sector];if(part.part===1){const opening=sectorIndex===1?`${ETHIK_KOMPASS.question}\n${ETHIK_KOMPASS.intro}\n\n${FRAME_OPENING}\n\n`:"";return`${opening}${needle}\n\nKapitel ${sectorIndex}: ${module.title}. ${arc.intro}\n\nAktueller Auftrag: ${task.story}`}return`${needle}\n\n${arc.continue}\n\nAktueller Auftrag: ${task.story}`}
function storyPanelMarkup(task,module,part){const story=frameStoryFor(task,module,part),html=escapeHtml(story).replace(/\n/g,"<br>");return`<details class="bible-panel story-panel"${part.part===1?" open":""}><summary>Rahmenerzählung: ${escapeHtml(task.title)}</summary><p>${html}</p>${speakButton(story)}</details>`}
function renderProgress(){document.getElementById("sessionLabel").textContent=sessionId;document.getElementById("tabletProgress").innerHTML=SECTORS.map(sector=>`<span class="${solved.has(sector.id)?"done":""}" title="${sector.name}"></span>`).join("");renderFogMap();renderCollectionHud();document.getElementById("tabletLock").classList.toggle("hidden",!locked);document.getElementById("tabletExcluded").classList.toggle("hidden",!excluded);const mode=WORK_MODES[activeWorkMode(sessionRows)];document.getElementById("phaseBanner").textContent=`Phase: ${activePhase(sessionRows)} · Modus: ${mode.name}`;const prompt=activePrompt(sessionRows),box=document.getElementById("livePrompt");box.classList.toggle("hidden",!prompt);box.innerHTML=prompt?`<b>Live-Auftrag der Lehrkraft</b><span>${escapeHtml(prompt)}</span>`:"";showPromptPopup(prompt);if(finaleRequested(sessionRows)&&!finaleSeen){finaleSeen=true;document.getElementById("finalePrompt").classList.remove("hidden")}}
function speak(text){if(!("speechSynthesis"in window))return;window.speechSynthesis.cancel();const utterance=new SpeechSynthesisUtterance(text);utterance.lang="de-DE";window.speechSynthesis.speak(utterance)}
function speakButton(text){return`<button class="comic-button speak-button" type="button" data-speak="${encodeURIComponent(text)}">🔊 Vorlesen</button>`}
function bindSpeakButtons(){const supported="speechSynthesis"in window;document.querySelectorAll(".speak-button").forEach(button=>{if(!supported){button.classList.add("hidden");return}button.addEventListener("click",()=>speak(decodeURIComponent(button.dataset.speak)))})}
function biblePanelMarkup(sectorId,open=true){const panel=BIBLE_PANELS[sectorId];if(!panel)return"";let noteIndex=0;const text=escapeHtml(panel.text).replace(/\[\[(.+?)\]\]/g,(_,word)=>`${word}<sup>${++noteIndex}</sup>`);const plainText=panel.text.replace(/\[\[(.+?)\]\]/g,"$1");const notes=(panel.notes||[]).map((note,index)=>`<li><sup>${index+1}</sup> ${escapeHtml(note)}</li>`).join("");return`<details class="bible-panel"${open?" open":""}><summary>Bibeltext-Hilfe (${escapeHtml(panel.reference)})</summary><p>${text}</p>${speakButton(plainText)}${notes?`<ol class="bible-notes">${notes}</ol>`:""}<small>Alle Spiele dieses Moduls sind nur mit diesem Textbezug lösbar.</small></details>`}
function productMarkup(task,next){return(!next||next.sector!==task.sector)?`<section class="product-card"><h3>Anonymer Merksatz für die Tafel</h3><p>Formuliert einen Satz, den ihr aus diesem Modul ins Plenum mitnehmt.</p><textarea id="productText" maxlength="220" placeholder="Unser Merksatz ..."></textarea></section>`:""}
function debateMarkup(){return`<section class="debate-card"><p class="comic-kicker">Debatten-Finale</p><div class="ethik-kompass-recap"><b>${escapeHtml(ETHIK_KOMPASS.question)}</b><p>${escapeHtml(ETHIK_KOMPASS.closingTask)}</p></div><h2>${escapeHtml(DEBATE_FINALE.question)}</h2><p><b>Plenumsbeiträge sind Belege.</b> Wählt eine Position und stützt sie mit Karten, Bibeltext und euren Entscheidungen. Eure Auswahl erscheint anonym in der Plenumsarena.</p><div class="debate-columns">${DEBATE_FINALE.positions.map((position,index)=>`<div><h3>Position ${index+1}</h3><p>${escapeHtml(position)}</p><div class="debate-drop" data-debate-slot="${index}"></div></div>`).join("")}</div><div class="debate-arguments">${DEBATE_FINALE.arguments.map(argument=>`<button class="argument-card" type="button">${escapeHtml(argument)}</button>`).join("")}</div><label class="reflection-label"><span>Eigene differenzierte Position</span><textarea id="debateOwnText" maxlength="220" placeholder="${escapeHtml(DEBATE_FINALE.ownPositionPrompt)}"></textarea></label><button class="comic-button" id="sendDebate" type="button">Plenumsbeiträge an Tafel senden</button></section>`}
function bindDebate(){document.querySelectorAll(".argument-card").forEach(button=>button.addEventListener("click",()=>{const side=button.dataset.side==="0"?"1":"0";button.dataset.side=side;document.querySelector(`[data-debate-slot="${side}"]`).append(button)}));document.getElementById("sendDebate")?.addEventListener("click",sendDebate)}
async function sendDebate(){const cards=[...document.querySelectorAll(".debate-drop .argument-card")].slice(0,4);for(const card of cards){await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:"control",status:"erledigt",event_type:"prompt",payload:`debate:${card.dataset.side||0}:${card.textContent.slice(0,180)}`})}const ownText=document.getElementById("debateOwnText")?.value.trim().replace(/\s+/g," ").slice(0,220);if(ownText)await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:"control",status:"erledigt",event_type:"prompt",payload:`debate:2:${ownText}`});document.getElementById("sendDebate").textContent="Gesendet"}
function openNotes(sectorId){const popup=document.getElementById("notesPopup");document.getElementById("notesText").value=groupNotes[sectorId]||"";popup.dataset.sector=sectorId;popup.classList.remove("hidden");document.getElementById("sendNotes").textContent="An Tafel senden"}
function saveNotes(){const popup=document.getElementById("notesPopup"),sectorId=popup.dataset.sector;if(!sectorId)return;groupNotes[sectorId]=document.getElementById("notesText").value;saveState()}
async function sendNotes(){const popup=document.getElementById("notesPopup"),sectorId=popup.dataset.sector,text=document.getElementById("notesText").value.trim().replace(/\s+/g," ").slice(0,500);saveNotes();if(!text)return;try{await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:"control",status:"erledigt",event_type:"prompt",payload:`product:notiz:${text}`})}catch(error){console.error(error)}document.getElementById("sendNotes").textContent="Gesendet"}
function showFeedbackCard(sectorId){if(feedbackSeen.has(sectorId))return;feedbackSeen.add(sectorId);document.getElementById("feedbackPopupText").textContent=feedbackFor(sectorId,sessionRows);document.getElementById("feedbackPopup").classList.remove("hidden")}
async function submitMiss(task){try{await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:"control",status:"erledigt",event_type:"prompt",payload:`miss:${taskIndex}:${task.type}:${task.sector}`})}catch(error){console.error(error)}}
async function submitProduct(sectorId){const text=document.getElementById("productText")?.value.trim().replace(/\s+/g," ").slice(0,220);if(!text)return;try{await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:"control",status:"erledigt",event_type:"prompt",payload:`product:${sectorId}:${text}`})}catch(error){console.error(error)}}
async function awardTask(task){if(completedGames.has(task.id))return;completedGames.add(task.id);if(task.card)localCards.push(task.card);saveState();try{if(task.card)await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:"control",status:"erledigt",event_type:"prompt",payload:`card:${task.card.type}:${task.card.name}`})}catch(error){console.error(error)}renderCollectionHud()}
function shuffle(items){return items.map((value,index)=>({value,index,sort:crypto.getRandomValues(new Uint32Array(1))[0]})).sort((a,b)=>a.sort-b.sort).map(item=>item)}
function choiceMarkup(task,multiple=false){const correct=Array.isArray(task.correct)?new Set(task.correct):new Set([task.correct]);return shuffle(task.answers).map(item=>`<label class="answer"><input type="${multiple?"checkbox":"radio"}" name="answer" data-correct="${correct.has(item.index)?"true":"false"}"><span>${escapeHtml(item.value)}</span></label>`).join("")}
function assignmentMarkup(task){return`<div class="assignment-game" data-assignment-type="${escapeHtml(task.type)}"><div class="assignment-slots">${task.items.map(([statement,correct],index)=>`<article class="match-card"><p>${escapeHtml(statement)}</p><button class="match-slot" type="button" data-correct="${escapeHtml(correct)}" data-slot="${index}"><span>Belegkarte ablegen</span></button></article>`).join("")}</div><div class="match-bank">${shuffle(task.correct).map(item=>`<button class="match-token" type="button" data-value="${escapeHtml(item.value)}">${escapeHtml(item.value)}</button>`).join("")}</div><button class="mini-action reset-match" type="button">Zuordnung leeren</button></div>`}
function puzzleMarkup(task){return`<div class="puzzle-game"><div class="puzzle-slots">${task.correct.map((correct,index)=>`<button class="puzzle-slot" type="button" data-correct="${escapeHtml(correct)}" data-slot="${index}"><small>${index+1}</small><span>frei</span></button>`).join("")}</div><div class="puzzle-bank">${shuffle(task.items).map(item=>`<button class="puzzle-piece" type="button" data-value="${escapeHtml(item.value)}">${escapeHtml(item.value)}</button>`).join("")}</div><button class="mini-action reset-puzzle" type="button">Puzzle leeren</button></div>`}
function levelsMarkup(task){return`<div class="level-game">${task.levels.map((level,index)=>`<fieldset class="level-card"><legend>${escapeHtml(level.title)}</legend><p>${escapeHtml(level.q)}</p>${shuffle(level.answers).map(answer=>`<label class="answer"><input type="radio" name="level-${index}" data-correct="${answer.index===level.correct?"true":"false"}"><span>${escapeHtml(answer.value)}</span></label>`).join("")}</fieldset>`).join("")}</div>`}
function unlockWordMarkup(task){return`<div class="unlock-word-game"><div class="letter-safe" data-word="${escapeHtml(task.clue)}" aria-live="polite">${task.clue.split("").map((letter,index)=>`<span data-letter-index="${index}">${index===0?escapeHtml(letter):"_"}</span>`).join("")}</div>${task.challenges.map((challenge,index)=>`<fieldset class="unlock-challenge" data-letters="${escapeHtml(challenge.letters)}"><legend>${index+1}. ${escapeHtml(challenge.q)}</legend>${shuffle(challenge.answers).map(answer=>`<label class="answer"><input type="radio" name="unlock-${index}" data-correct="${answer.index===challenge.correct?"true":"false"}"><span>${escapeHtml(answer.value)}</span></label>`).join("")}</fieldset>`).join("")}<input class="word-input" name="word-answer" autocomplete="off" placeholder="Freigeschaltetes Schlüsselwort eingeben"><small>Jede richtige Teilentscheidung deckt Buchstaben auf. Am Ende muss das ganze Wort stimmen.</small></div>`}
function chatMarkup(task){return`<div class="chat-game" aria-live="polite">${task.chat.map((step,index)=>`<section class="chat-step ${index?"hidden":""} ${index?"":"revealed"}" data-chat-step="${index}"><div class="chat-bubble incoming"><b>${escapeHtml(step.from)}</b><span>${escapeHtml(step.text)}</span></div><div class="chat-choices">${shuffle(step.choices).map(choice=>`<button class="chat-choice" type="button" data-correct="${choice.index===step.correct?"true":"false"}">${escapeHtml(choice.value)}</button>`).join("")}</div><div class="typing-dots hidden" data-typing-for="${index+1}" aria-label="schreibt"><i></i><i></i><i></i></div><div class="chat-bubble system hidden">${escapeHtml(step.reply)}</div></section>`).join("")}</div>`}
function logicBuilderMarkup(task){return`<div class="foundation-game"><div class="foundation-slots">${task.correct.map((correct,index)=>`<button class="logic-slot" type="button" data-correct="${escapeHtml(correct)}"><small>${index+1}</small><span>Baustein setzen</span></button>`).join("")}</div><div class="foundation-bank">${shuffle(task.items).map(item=>`<button class="logic-stone" type="button" data-value="${escapeHtml(item.value)}">${escapeHtml(item.value)}</button>`).join("")}</div><button class="mini-action reset-logic" type="button">Fundament neu bauen</button></div>`}
function pathMarkup(task){return`<div class="path-game">${task.steps.map((step,index)=>`<fieldset class="path-card"><legend>${index+1}. ${escapeHtml(step.title)}</legend><p>${escapeHtml(step.q)}</p>${shuffle(step.answers).map(answer=>`<label class="answer"><input type="radio" name="path-${index}" data-correct="${answer.index===step.correct?"true":"false"}"><span>${escapeHtml(answer.value)}</span></label>`).join("")}</fieldset>`).join("")}</div>`}
function finalQuestMarkup(task){const recap=localCards.length?`<div class="module-context"><p>Eure bisherigen Belegkarten aus dem Lehrkreis - nutzt sie als Bibelbelege für eure Begründung:</p><div class="reward-row">${localCards.map(card=>`<span>${escapeHtml(card.type)}: ${escapeHtml(card.name)}</span>`).join("")}</div></div>`:"";return`${recap}<div class="finalquest-game">${task.phases.map((phase,index)=>`<fieldset class="path-card"><legend>${index+1}. ${escapeHtml(phase.title)}</legend><p>${escapeHtml(phase.q)}</p>${shuffle(phase.answers).map(answer=>`<label class="answer"><input type="radio" name="final-${index}" data-correct="${answer.index===phase.correct?"true":"false"}"><span>${escapeHtml(answer.value)}</span></label>`).join("")}</fieldset>`).join("")}<label class="reflection-label"><span>Begründung für die Plenumsarena</span><textarea id="finalReason" placeholder="Wir bauen auf Fels, weil ..."></textarea><small>Die Begründung hilft euch später beim Argumentieren. Sie wird nicht benotet.</small></label></div>`}
function wimmelMarkup(task){const targets=(task.hotspots||[]).filter(spot=>spot.correct);return`<div class="wimmel-brief"><p><b>Diese Symbole sucht ihr:</b></p><div class="wimmel-targets">${targets.map((spot,index)=>`<span data-target="${index}"><i>${escapeHtml(spot.symbol||"•")}</i>${escapeHtml(spot.label)}</span>`).join("")}</div></div><div class="wimmel-progress"><b id="wimmelCount">0</b><span> / ${targets.length} Funde</span></div><div class="wimmel-game" role="group" aria-label="KI-Wimmelbild"><img class="wimmel-image" src="${escapeHtml(task.image)}" alt="Comic-Wimmelbild zur Bergpredigt und zum Vaterunser">${targets.map((spot,index)=>`<button class="wimmel-spot" type="button" data-index="${index}" data-symbol="${escapeHtml(spot.symbol||"•")}" data-label="${escapeHtml(spot.label)}" data-correct="true" style="--x:${spot.x}%;--y:${spot.y}%" aria-label="${escapeHtml(spot.label)} finden"><span>${escapeHtml(spot.label)}</span></button>`).join("")}</div><div class="found-shelf" id="foundTray" aria-live="polite"><b>Fund-Regal</b><div>${targets.map((spot,index)=>`<span class="shelf-slot" data-shelf="${index}"><i>${escapeHtml(spot.symbol||"•")}</i><small>${escapeHtml(spot.label)}</small></span>`).join("")}</div></div>`}
function answerMarkup(task){if(task.type==="levels")return levelsMarkup(task);if(task.type==="unlockword")return unlockWordMarkup(task);if(task.type==="chat")return chatMarkup(task);if(task.type==="wimmel")return wimmelMarkup(task);if(task.type==="path")return pathMarkup(task);if(task.type==="finalquest")return finalQuestMarkup(task);if(task.type==="quest")return choiceMarkup(task,true);if(task.type==="puzzle")return puzzleMarkup(task);if(task.type==="logic")return logicBuilderMarkup(task);if(["match","cards"].includes(task.type))return assignmentMarkup(task);return choiceMarkup(task)}
function values(name){return[...document.querySelectorAll(`[name="${name}"]`)].map(input=>input.value)}
function normalizeWord(value){return String(value||"").trim().toLowerCase().replace(/\s+/g,"")}
function isCorrect(task){if(task.type==="levels")return task.levels.every((_,index)=>document.querySelector(`input[name="level-${index}"]:checked`)?.dataset.correct==="true");if(task.type==="unlockword"){const answer=normalizeWord(document.querySelector('[name="word-answer"]')?.value),valid=[task.answer,...(task.alternatives||[])].map(normalizeWord),questions=task.challenges.every((_,index)=>document.querySelector(`input[name="unlock-${index}"]:checked`)?.dataset.correct==="true");return questions&&valid.includes(answer)}if(task.type==="chat")return task.chat.every((_,index)=>document.querySelector(`[data-chat-step="${index}"] .chat-choice.selected`)?.dataset.correct==="true");if(task.type==="wimmel"){const buttons=[...document.querySelectorAll(".wimmel-spot")];return buttons.every(button=>button.classList.contains("found")===(button.dataset.correct==="true"))}if(task.type==="path")return task.steps.every((_,index)=>document.querySelector(`input[name="path-${index}"]:checked`)?.dataset.correct==="true");if(task.type==="finalquest")return task.phases.every((_,index)=>document.querySelector(`input[name="final-${index}"]:checked`)?.dataset.correct==="true");if(task.type==="quest"){const inputs=[...document.querySelectorAll('input[name="answer"]')];return inputs.some(input=>input.checked)&&inputs.every(input=>input.checked===(input.dataset.correct==="true"))}if(task.type==="puzzle")return[...document.querySelectorAll(".puzzle-slot")].every(slot=>slot.dataset.value&&slot.dataset.value===slot.dataset.correct);if(task.type==="logic")return[...document.querySelectorAll(".logic-slot")].every(slot=>slot.dataset.value&&slot.dataset.value===slot.dataset.correct);if(["match","cards"].includes(task.type))return[...document.querySelectorAll(".match-slot")].every(slot=>slot.dataset.value&&slot.dataset.value===slot.dataset.correct);return false}
function bindSpecialGames(){document.querySelectorAll(".puzzle-piece").forEach(piece=>piece.addEventListener("click",()=>{const slot=[...document.querySelectorAll(".puzzle-slot")].find(item=>!item.dataset.value);if(!slot)return;slot.dataset.value=piece.dataset.value;slot.querySelector("span").textContent=piece.dataset.value;piece.disabled=true}));document.querySelectorAll(".puzzle-slot").forEach(slot=>slot.addEventListener("click",()=>{if(!slot.dataset.value)return;const piece=[...document.querySelectorAll(".puzzle-piece")].find(item=>item.dataset.value===slot.dataset.value&&item.disabled);if(piece)piece.disabled=false;delete slot.dataset.value;slot.querySelector("span").textContent="frei"}));document.querySelector(".reset-puzzle")?.addEventListener("click",()=>{document.querySelectorAll(".puzzle-slot").forEach(slot=>{delete slot.dataset.value;slot.querySelector("span").textContent="frei"});document.querySelectorAll(".puzzle-piece").forEach(piece=>piece.disabled=false)});document.querySelectorAll(".match-token").forEach(token=>token.addEventListener("click",()=>{const slot=[...document.querySelectorAll(".match-slot")].find(item=>!item.dataset.value);if(!slot)return;slot.dataset.value=token.dataset.value;slot.querySelector("span").textContent=token.dataset.value;token.disabled=true}));document.querySelectorAll(".match-slot").forEach(slot=>slot.addEventListener("click",()=>{if(!slot.dataset.value)return;const token=[...document.querySelectorAll(".match-token")].find(item=>item.dataset.value===slot.dataset.value&&item.disabled);if(token)token.disabled=false;delete slot.dataset.value;slot.querySelector("span").textContent="Belegkarte ablegen"}));document.querySelector(".reset-match")?.addEventListener("click",()=>{document.querySelectorAll(".match-slot").forEach(slot=>{delete slot.dataset.value;slot.querySelector("span").textContent="Belegkarte ablegen"});document.querySelectorAll(".match-token").forEach(token=>token.disabled=false)});document.querySelectorAll(".logic-stone").forEach(stone=>stone.addEventListener("click",()=>{const slot=[...document.querySelectorAll(".logic-slot")].find(item=>!item.dataset.value);if(!slot)return;slot.dataset.value=stone.dataset.value;slot.querySelector("span").textContent=stone.dataset.value;stone.disabled=true}));document.querySelectorAll(".logic-slot").forEach(slot=>slot.addEventListener("click",()=>{if(!slot.dataset.value)return;const stone=[...document.querySelectorAll(".logic-stone")].find(item=>item.dataset.value===slot.dataset.value&&item.disabled);if(stone)stone.disabled=false;delete slot.dataset.value;slot.querySelector("span").textContent="Baustein setzen"}));document.querySelector(".reset-logic")?.addEventListener("click",()=>{document.querySelectorAll(".logic-slot").forEach(slot=>{delete slot.dataset.value;slot.querySelector("span").textContent="Baustein setzen"});document.querySelectorAll(".logic-stone").forEach(stone=>stone.disabled=false)});const updateLetters=()=>{const safe=document.querySelector(".letter-safe");if(safe){const word=safe.dataset.word||"",revealed=new Set([0]);let cursor=1;document.querySelectorAll(".unlock-challenge").forEach(challenge=>{const checked=challenge.querySelector("input:checked"),count=String(challenge.dataset.letters||"").length;if(checked?.dataset.correct==="true")for(let i=0;i<count;i++)revealed.add(cursor+i);cursor+=count});[...safe.querySelectorAll("span")].forEach((span,index)=>span.textContent=revealed.has(index)?word[index]:"_")}};document.querySelectorAll(".unlock-challenge input").forEach(input=>input.addEventListener("change",updateLetters));document.querySelectorAll(".wimmel-spot").forEach(button=>button.addEventListener("click",()=>button.classList.toggle("selected")))}
function enhanceSpecialGames(task){
  document.querySelectorAll(".chat-choice").forEach(button=>button.addEventListener("click",()=>{
    const step=button.closest(".chat-step"),index=Number(step?.dataset.chatStep||0);
    step.querySelectorAll(".chat-choice").forEach(item=>item.classList.remove("selected","wrong"));
    button.classList.add("selected");
    if(button.dataset.correct==="true"){
      step.querySelectorAll(".chat-choice").forEach(item=>item.disabled=true);
      step.querySelector(".chat-bubble.system")?.classList.remove("hidden");
      const next=document.querySelector(`[data-chat-step="${index+1}"]`),typing=step.querySelector(`[data-typing-for="${index+1}"]`);
      if(next&&next.classList.contains("hidden")){
        typing?.classList.remove("hidden");
        setTimeout(()=>{typing?.classList.add("hidden");next.classList.remove("hidden");requestAnimationFrame(()=>next.classList.add("revealed"));next.scrollIntoView({behavior:"smooth",block:"nearest"})},850);
      }
    }else{
      button.classList.add("wrong");
    }
  }));
  const flyToShelf=(button,slot)=>{
    if(!slot)return;
    const from=button.getBoundingClientRect(),to=slot.getBoundingClientRect(),flyer=document.createElement("span");
    flyer.className="wimmel-flyer";
    flyer.textContent=button.dataset.symbol||"•";
    flyer.style.left=`${from.left+from.width/2}px`;
    flyer.style.top=`${from.top+from.height/2}px`;
    flyer.style.setProperty("--tx",`${to.left+to.width/2-from.left-from.width/2}px`);
    flyer.style.setProperty("--ty",`${to.top+to.height/2-from.top-from.height/2}px`);
    document.body.append(flyer);
    flyer.addEventListener("animationend",()=>flyer.remove(),{once:true});
  };
  const updateWimmel=button=>{
    const found=[...document.querySelectorAll(".wimmel-spot.found")],count=document.getElementById("wimmelCount");
    if(count)count.textContent=String(found.length);
    document.querySelectorAll(".wimmel-targets [data-target]").forEach(target=>target.classList.toggle("found",!!document.querySelector(`.wimmel-spot.found[data-index="${target.dataset.target}"]`)));
    document.querySelectorAll(".shelf-slot").forEach(slot=>{
      const foundButton=document.querySelector(`.wimmel-spot.found[data-index="${slot.dataset.shelf}"]`);
      slot.classList.toggle("filled",!!foundButton);
      if(foundButton){slot.querySelector("i").textContent=foundButton.dataset.symbol||"•";slot.querySelector("small").textContent=foundButton.dataset.label||foundButton.textContent.trim()}
    });
    if(button)flyToShelf(button,document.querySelector(`.shelf-slot[data-shelf="${button.dataset.index}"]`));
  };
  document.querySelectorAll(".wimmel-spot").forEach(button=>button.addEventListener("click",event=>{
    event.stopImmediatePropagation();
    event.preventDefault();
    if(button.classList.contains("found"))return;
    button.classList.add("found");
    button.disabled=true;
    updateWimmel(button);
  },true));
}
function renderTask(){
  attempts=0;
  renderProgress();
  const card=document.getElementById("taskCard");
  if(taskIndex>=TASKS.length){
    card.className="task-card final-card";
    card.innerHTML=finaleRequested(sessionRows)?`${tabletMapMarkup()}${debateMarkup()}`:`<p class='comic-kicker'>Mission geschafft</p><h2>Ihr seid bereit für das Finale!</h2><p>Wartet auf die Plenumsarena der Lehrkraft.</p>${tabletMapMarkup()}`;
    bindDebate();
    return;
  }
  const task=TASKS[taskIndex],next=TASKS[taskIndex+1],sector=SECTORS.find(s=>s.id===task.sector),module=moduleFor(task.sector,sessionRows),part=stationPart(taskIndex),isCoop=activeWorkMode(sessionRows)==="cooperative",state=sessionCompletion.get(sector.id)||{count:0,required:isCoop?groupTarget:1};
  card.className=`task-card task-type-${task.type}`;
  card.innerHTML=`<div class="station-header"><span class="station-number">${sector.name} · Spiel ${part.part}/${part.total} · Schwierigkeit ${task.difficulty}</span><b>${taskSkillLabel(task)}</b><button class="comic-button mini-action" id="openNotes" type="button">📝 Notizblock</button></div><p class="coop-note">${isCoop?`${state.count}/${state.required} aktive Gruppen haben dieses Modul gesichert.`:"Euer Modulabschluss kann die Tafel öffnen."}</p>${storyPanelMarkup(task,module,part)}${biblePanelMarkup(task.sector,part.part===1)}<h2>${escapeHtml(task.title)}</h2><h3>${escapeHtml(task.question)}</h3>${speakButton(task.question)}<div class="answers">${answerMarkup(task)}</div>${productMarkup(task,next)}<div class="feedback hidden" id="feedback" aria-live="polite"></div><div class="task-actions"><button class="comic-button" id="checkAnswer" type="button">Spiel prüfen</button><button class="comic-button next-task hidden" id="nextTask" type="button">Weiter →</button></div>`;
  bindSpecialGames();
  enhanceSpecialGames(task);
  bindSpeakButtons();
  document.getElementById("checkAnswer").addEventListener("click",checkAnswer);
  document.getElementById("nextTask").addEventListener("click",advance);
  document.getElementById("openNotes").addEventListener("click",()=>openNotes(task.sector));
}
function bindGlossaryTerms(){document.querySelectorAll(".glossary-term").forEach(button=>button.addEventListener("click",()=>{const item=GLOSSARY[Number(button.dataset.glossary)];if(!item)return;document.getElementById("glossaryTermTitle").textContent=item.term;document.getElementById("glossaryTermText").textContent=item.definition;document.getElementById("glossaryTermPopup").classList.remove("hidden")}))}
async function checkAnswer(){if(locked||excluded)return;const task=TASKS[taskIndex],feedback=document.getElementById("feedback");if(!isCorrect(task)){attempts++;submitMiss(task);feedback.className="feedback bad";feedback.textContent=attempts>=3&&task.hint2?`Zusätzlicher Hinweis: ${task.hint2}`:attempts>1?`Noch nicht tragfähig. Hinweis: ${task.hint}`:"Noch nicht. Nutzt den Bibeltext genau und besprecht eure Wahl.";return}feedback.className="feedback good";document.querySelectorAll(".task-card input,.task-card textarea,.task-card select,.task-card button:not(.next-task)").forEach(input=>input.disabled=true);feedback.innerHTML=`✓ ${glossaryLinkMarkup(task.success)}`;bindGlossaryTerms();document.getElementById("checkAnswer").classList.add("hidden");document.getElementById("nextTask").classList.remove("hidden");await awardTask(task)}
async function advance(){if(locked||excluded)return;const current=TASKS[taskIndex],next=TASKS[taskIndex+1],stationComplete=!next||next.sector!==current.sector,button=document.getElementById("nextTask");button.disabled=true;try{if(stationComplete&&!solved.has(current.sector)){await submitProduct(current.sector);await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:current.sector,status:"erledigt"});solved.add(current.sector)}taskIndex++;saveState();renderTask();if(stationComplete)showFeedbackCard(current.sector)}catch(error){console.error(error);button.disabled=false;document.getElementById("feedback").className="feedback bad";document.getElementById("feedback").textContent="Das Spiel ist gelöst, aber die Übertragung hat nicht geklappt. Bitte versucht es erneut."}}
async function refreshControl(){try{sessionRows=await readProgress(db,sessionId);locked=isSessionLocked(sessionRows);excluded=groupId?isGroupExcluded(sessionRows,groupId):false;groupTarget=effectiveGroupTargetFromRows(sessionRows);sessionCompletion=sectorCompletion(sessionRows);renderProgress();if(taskIndex>=TASKS.length)renderTask()}catch(error){console.error(error)}}
function subscribeControl(){if(!db)return;if(liveChannel)db.removeChannel(liveChannel);liveChannel=db.channel(`tablet-control-${sessionId}`).on("postgres_changes",{event:"INSERT",schema:"public",table:"fortschritt",filter:`session_id=eq.${sessionId}`},()=>refreshControl()).subscribe()}
document.getElementById("groupForm").addEventListener("submit",async event=>{event.preventDefault();groupId=sanitizeGroupId(document.getElementById("groupInput").value);const chosenAvatar=selectedAvatar;if(groupId.length<2)return;restoreState();selectedAvatar=chosenAvatar;saveAvatarState();try{await markDone(db,{session_id:sessionId,gruppen_id:groupId,sektor:"control",status:"erledigt",event_type:"manual",payload:`avatar:${selectedAvatar}`})}catch(error){console.error(error)}await refreshControl();subscribeControl();document.getElementById("groupSetup").classList.add("hidden");document.getElementById("missionArea").classList.remove("hidden");document.getElementById("groupLabel").innerHTML=`<span class="avatar-token tiny" style="--avatar-pos:${avatarById(selectedAvatar).pos}"></span> Gruppe: ${escapeHtml(groupId)}`;renderTask()});
async function downloadGroupProtocol(){try{await refreshControl()}catch(error){console.error(error)}const text=groupProtocolText(sessionRows,sessionId,groupId),blob=new Blob([text],{type:"text/plain;charset=utf-8"}),url=URL.createObjectURL(blob),link=document.createElement("a");link.href=url;link.download=`bergpredigt-protokoll-${sessionId}-${groupId}.txt`;link.click();URL.revokeObjectURL(url)}
document.getElementById("downloadProtocol").addEventListener("click",downloadGroupProtocol);
document.getElementById("changeGroup").addEventListener("click",()=>{groupId="";taskIndex=0;solved=new Set();completedGames=new Set();localCards=[];groupNotes={};document.getElementById("groupSetup").classList.remove("hidden");document.getElementById("missionArea").classList.add("hidden");document.getElementById("groupInput").focus()});
